// ── Tests for handleSubmit  ──

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { handleSubmit } from './handleSubmit';

describe('handleSubmit', () => {
  let eventMock: { preventDefault: () => void; target: { elements: Record<string, { value: string }> } };

  beforeEach(() => {
    eventMock = {
      preventDefault: vi.fn(),
      target: {
        elements: {}
      }
    };
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('should handle happy path - prevent default and process valid form submission', () => {
    const callback = vi.fn();
    eventMock.target.elements['email'] = { value: 'test@example.com' };
    eventMock.target.elements['password'] = { value: 'password123' };

    handleSubmit(eventMock as any, callback);

    expect(eventMock.preventDefault).toHaveBeenCalled();
    expect(callback).toHaveBeenCalledWith({ email: 'test@example.com', password: 'password123' });
  });

  it('should handle edge case - process submission with optional fields empty', () => {
    const callback = vi.fn();
    eventMock.target.elements['email'] = { value: 'user@domain.com' };
    eventMock.target.elements['phone'] = { value: '' };

    handleSubmit(eventMock as any, callback);

    expect(eventMock.preventDefault).toHaveBeenCalled();
    expect(callback).toHaveBeenCalledWith({ email: 'user@domain.com', phone: '' });
  });

  it('should handle null/empty - do nothing when event is null', () => {
    const callback = vi.fn();

    handleSubmit(null as any, callback);

    expect(callback).not.toHaveBeenCalled();
    expect(eventMock.preventDefault).not.toHaveBeenCalled();
  });
});